// Pull each run's per-index "untouched outside `index`" forall into the
// proof context with aligned triggers, so z3 can instantiate them together.
assert(forall|i: int|
    #![trigger post1_self_.page_array@[i]]
    #![trigger pre_self_.page_array@[i]]
    0 <= i < NUM_PAGES && i != index ==>
        post1_self_.page_array@[i] =~= pre_self_.page_array@[i]);
assert(forall|i: int|
    #![trigger post2_self_.page_array@[i]]
    #![trigger pre_self_.page_array@[i]]
    0 <= i < NUM_PAGES && i != index ==>
        post2_self_.page_array@[i] =~= pre_self_.page_array@[i]);

// Pointwise equality of the two page-array views. The body splits on
// whether `i` is the (single) touched index; in both branches the
// per-field ensures of `set_mapping` line up the two `Page` records.
assert forall|i: int|
    0 <= i < NUM_PAGES implies
        post1_self_.page_array@[i] =~= post2_self_.page_array@[i] by {
    if i == index as int {
        // At i == index, every Page field of post1 and post2 is tied to
        // pre_self_'s corresponding field (addr, state, is_io_page,
        // rev_pointer, ref_count, owning_container, io_mappings), and
        // `mappings` is `mapping` for both runs. Field-wise equality
        // gives Page-level =~=.
    } else {
        // i != index: both re-asserted foralls fire on the trigger
        // `post1_self_.page_array@[i]` / `post2_self_.page_array@[i]`,
        // forcing both views to equal `pre_self_.page_array@[i]`.
    }
}

// Lift pointwise Page equality to sequence extensionality on page_array@.
assert(post1_self_.page_array@ =~= post2_self_.page_array@);
